#include <bits/stdc++.h>
using namespace std;
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char buf[1005]; scanf("%s",buf);
        string s(buf);
        int n; scanf("%d",&n);
        vector<string> pat(n);
        for(int i=0;i<n;i++){
            scanf("%s",buf);
            pat[i]=buf;
        }
        int m=s.size();
        const int INF=1e9;
        vector<int> dp(m+1,INF);
        dp[0]=0;
        for(int i=1;i<=m;i++){
            dp[i]=dp[i-1]+1; // keep current char
            for(const string &p:pat){
                int L=p.size();
                if(L<=i && s.compare(i-L,L,p)==0){
                    dp[i]=min(dp[i],dp[i-L]);
                }
            }
        }
        printf("%d\n",dp[m]);
    }
    return 0;
}

