const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let results = [];
for (let t = 0; t < T; t++) {
  const s = lines[idx++].trim();
  const n = parseInt(lines[idx++].trim(), 10);
  const patterns = [];
  for (let i = 0; i < n; i++) patterns.push(lines[idx++].trim());
  const m = s.length;
  const INF = 1e9;
  const dp = new Array(m + 1).fill(INF);
  dp[0] = 0;
  for (let i = 1; i <= m; i++) {
    dp[i] = dp[i - 1] + 1; // keep character
    for (const p of patterns) {
      const L = p.length;
      if (L <= i && s.slice(i - L, i) === p) {
        dp[i] = Math.min(dp[i], dp[i - L]);
      }
    }
  }
  results.push(String(dp[m]));
}
console.log(results.join('\n'));
